;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] WAY == "s"

; イベント＆リーゼル妊娠開始
[if exp='f.dayOfLieselPregnant === void']
	@eval exp='f.dayOfLieselPregnant = game.date'
	@addevent name=リーゼル num=4
	@jump storage="main08.scn" target=*revenge_3
[else]
	[texton]
	Let's not go in here. I don't want to see what's going on in the orgy room.[k]
	[textoff]
	@walk move=e
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("maxLife", 15)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP permanently increased by 15!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("piety", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Faith permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.heat += 10'
@eval exp='game.curTarget.setStatus(o.酩酊, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> got drunk!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.heat += 10'
@eval exp='game.curTarget.setStatus(o.酩酊, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> got drunk!"'

[eventoff]
;-------------------------------------------------------------------------------
